     1→"use client";
     2→
     3→import { useState, useEffect, useCallback } from "react";
     4→import {
     5→  getAdminQueue,
     6→  getAdminSession,
     7→  getBoothStats,
     8→  getSTTConfig,
     9→  updateSTTConfig,
    10→  skipQueueUser,
    11→  forceEndSession,
    12→  startMirrorSession,
    13→  advanceQueue,
    14→  type AdminQueueEntry,
    15→  type AdminSessionInfo,
    16→  type BoothStats,
    17→  type STTConfig,
    18→} from "@/lib/api";
    19→
    20→const POLL_INTERVAL = 10_000;
    21→
    22→export default function AdminPage() {
    23→  const [queue, setQueue] = useState<AdminQueueEntry[]>([]);
    24→  const [session, setSession] = useState<AdminSessionInfo | null>(null);
    25→  const [stats, setStats] = useState<BoothStats | null>(null);
    26→  const [sttConfig, setSttConfig] = useState<STTConfig | null>(null);
    27→  const [loading, setLoading] = useState(true);
    28→
    29→  const refresh = useCallback(async () => {
    30→    try {
    31→      const [q, s, st, stt] = await Promise.all([
    32→        getAdminQueue(),
    33→        getAdminSession(),
    34→        getBoothStats(),
    35→        getSTTConfig(),
    36→      ]);
    37→      setQueue(q);
    38→      setSession(s);
    39→      setStats(st);
    40→      setSttConfig(stt);
    41→    } catch (err) {
    42→      console.error("[Admin] Refresh failed:", err);
    43→    } finally {
    44→      setLoading(false);
    45→    }
    46→  }, []);
    47→
    48→  useEffect(() => {
    49→    refresh();
    50→    const timer = setInterval(refresh, POLL_INTERVAL);
    51→    return () => clearInterval(timer);
    52→  }, [refresh]);
    53→
    54→  const handleSkip = useCallback(
    55→    async (userId: string) => {
    56→      await skipQueueUser(userId);
    57→      refresh();
    58→    },
    59→    [refresh]
    60→  );
    61→
    62→  const handleForceEnd = useCallback(async () => {
    63→    await forceEndSession();
    64→    refresh();
    65→  }, [refresh]);
    66→
    67→  const handleStartSession = useCallback(
    68→    async (userId: string) => {
    69→      await startMirrorSession(userId);
    70→      refresh();
    71→    },
    72→    [refresh]
    73→  );
    74→
    75→  const handleAdvance = useCallback(async () => {
    76→    await advanceQueue();
    77→    refresh();
    78→  }, [refresh]);
    79→
    80→  if (loading) {
    81→    return (
    82→      <main className="min-h-screen bg-zinc-50 flex items-center justify-center">
    83→        <p className="text-zinc-400">Loading admin panel...</p>
    84→      </main>
    85→    );
    86→  }
    87→
    88→  const activeEntry = queue.find((q) => q.status === "active");
    89→  const waitingEntries = queue.filter((q) => q.status === "waiting");
    90→
    91→  return (
    92→    <main className="min-h-screen bg-zinc-50 p-6">
    93→      <div className="max-w-4xl mx-auto">
    94→        <div className="flex items-center justify-between mb-8">
    95→          <h1 className="text-2xl font-bold">Mirrorless Admin</h1>
    96→          <button
    97→            onClick={refresh}
    98→            className="text-sm text-zinc-500 hover:text-zinc-900 underline"
    99→          >
   100→            Refresh
   101→          </button>
   102→        </div>
   103→
   104→        {/* Booth Stats */}
   105→        {stats && (
   106→          <div className="grid grid-cols-4 gap-4 mb-8">
   107→            <StatCard label="Users Today" value={stats.total_users_today} />
   108→            <StatCard
   109→              label="Avg Session"
   110→              value={`${Math.round(stats.avg_session_seconds)}s`}
   111→            />
   112→            <StatCard label="Items Shown" value={stats.total_items_shown} />
   113→            <StatCard label="Items Liked" value={stats.total_items_liked} />
   114→          </div>
   115→        )}
   116→
   117→        {/* Current Session */}
   118→        <section className="bg-white rounded-xl border border-zinc-200 p-6 mb-6">
   119→          <h2 className="text-lg font-semibold mb-4">Current Session</h2>
   120→          {session ? (
   121→            <div className="flex items-center justify-between">
   122→              <div>
   123→                <p className="font-medium">{session.name}</p>
   124→                <p className="text-sm text-zinc-500">
   125→                  API calls: {session.api_calls} | Items: {session.items_shown} shown, {session.items_liked} liked
   126→                </p>
   127→              </div>
   128→              <button
   129→                onClick={handleForceEnd}
   130→                className="bg-red-500 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-600"
   131→              >
   132→                Force End
   133→              </button>
   134→            </div>
   135→          ) : activeEntry ? (
   136→            <div className="flex items-center justify-between">
   137→              <div>
   138→                <p className="font-medium">{activeEntry.name}</p>
   139→                <p className="text-sm text-zinc-500">Waiting at mirror (no session started)</p>
   140→              </div>
   141→              <div className="flex gap-2">
   142→                <button
   143→                  onClick={() => handleStartSession(activeEntry.user_id)}
   144→                  className="bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-600"
   145→                >
   146→                  Start Session
   147→                </button>
   148→                <button
   149→                  onClick={() => handleSkip(activeEntry.user_id)}
   150→                  className="bg-zinc-200 text-zinc-700 px-4 py-2 rounded-lg text-sm font-medium hover:bg-zinc-300"
   151→                >
   152→                  Skip
   153→                </button>
   154→              </div>
   155→            </div>
   156→          ) : (
   157→            <p className="text-zinc-400">No active session</p>
   158→          )}
   159→        </section>
   160→
   161→        {/* Queue */}
   162→        <section className="bg-white rounded-xl border border-zinc-200 p-6 mb-6">
   163→          <div className="flex items-center justify-between mb-4">
   164→            <h2 className="text-lg font-semibold">
   165→              Queue ({waitingEntries.length} waiting)
   166→            </h2>
   167→            {waitingEntries.length > 0 && !activeEntry && (
   168→              <button
   169→                onClick={handleAdvance}
   170→                className="text-sm text-blue-600 hover:underline"
   171→              >
   172→                Advance Next
   173→              </button>
   174→            )}
   175→          </div>
   176→          {waitingEntries.length === 0 ? (
   177→            <p className="text-zinc-400">Queue is empty</p>
   178→          ) : (
   179→            <div className="divide-y divide-zinc-100">
   180→              {waitingEntries.map((entry) => (
   181→                <div
   182→                  key={entry.id}
   183→                  className="flex items-center justify-between py-3"
   184→                >
   185→                  <div className="flex items-center gap-3">
   186→                    <span className="w-8 h-8 rounded-full bg-zinc-100 flex items-center justify-center text-sm font-medium">
   187→                      {entry.position}
   188→                    </span>
   189→                    <span className="font-medium">{entry.name}</span>
   190→                  </div>
   191→                  <button
   192→                    onClick={() => handleSkip(entry.user_id)}
   193→                    className="text-sm text-red-500 hover:underline"
   194→                  >
   195→                    Skip
   196→                  </button>
   197→                </div>
   198→              ))}
   199→            </div>
   200→          )}
   201→        </section>
   202→
   203→        {/* STT Settings */}
   204→        {sttConfig && (
   205→          <STTSettings config={sttConfig} onChange={setSttConfig} />
   206→        )}
   207→      </div>
   208→    </main>
   209→  );
   210→}
   211→
   212→function StatCard({ label, value }: { label: string; value: string | number }) {
   213→  return (
   214→    <div className="bg-white rounded-xl border border-zinc-200 p-4 text-center">
   215→      <p className="text-2xl font-bold">{value}</p>
   216→      <p className="text-xs text-zinc-500 mt-1">{label}</p>
   217→    </div>
   218→  );
   219→}
   220→
   221→const STT_MODELS = [
   222→  { value: "nova-2", label: "Nova 2 (default)" },
   223→  { value: "nova-2-general", label: "Nova 2 General" },
   224→  { value: "nova-2-phonecall", label: "Nova 2 Phone Call" },
   225→  { value: "nova-2-meeting", label: "Nova 2 Meeting" },
   226→];
   227→
   228→function STTSettings({
   229→  config,
   230→  onChange,
   231→}: {
   232→  config: STTConfig;
   233→  onChange: (config: STTConfig) => void;
   234→}) {
   235→  const [localUtterance, setLocalUtterance] = useState(config.utterance_end_ms);
   236→  const [saving, setSaving] = useState(false);
   237→
   238→  const save = useCallback(
   239→    async (patch: Partial<STTConfig>) => {
