   605→      }
   606→
   607→      // Thumbs → hold-to-confirm (update last-seen time each frame)
   608→      const now = Date.now();
   609→      holdLastSeenRef.current = now;
   610→
   611→      // If gesture type changed, reset and start a fresh hold
   612→      if (holdGestureRef.current !== gesture.type) {
