   886→              style={{
   887→                padding: "16px 48px",
   888→                fontSize: "1.2rem",
   889→                fontWeight: 600,
   890→                color: "#fff",
   891→                background: "rgba(100, 140, 255, 0.8)",
   892→                border: "none",
   893→                borderRadius: 12,
   894→                cursor: "pointer",
   895→                boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   896→              }}
   897→            >
