     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→
     5→const DEEPGRAM_API_KEY = process.env.NEXT_PUBLIC_DEEPGRAM_API_KEY || "";
     6→const MAX_RECONNECTS = 3;
     7→
     8→export interface DeepgramSTTConfig {
     9→  utterance_end_ms: number;
    10→  model: string;
    11→  smart_format: boolean;
    12→}
    13→
    14→const DEFAULT_CONFIG: DeepgramSTTConfig = {
    15→  utterance_end_ms: 1500,
    16→  model: "nova-2",
    17→  smart_format: true,
    18→};
    19→
    20→function buildDeepgramUrl(config: DeepgramSTTConfig): string {
    21→  const params = new URLSearchParams({
    22→    model: config.model,
    23→    smart_format: String(config.smart_format),
    24→    interim_results: "true",
    25→    vad_events: "true",
    26→    utterance_end_ms: String(config.utterance_end_ms),
    27→    encoding: "linear16",
    28→    sample_rate: "16000",
    29→  });
    30→  return `wss://api.deepgram.com/v1/listen?${params}`;
    31→}
    32→
    33→export interface UseDeepgramSTTReturn {
    34→  isListening: boolean;
    35→  transcript: string;
    36→  interimTranscript: string;
    37→  startListening: () => void;
    38→  stopListening: () => void;
    39→}
    40→
    41→export function useDeepgramSTT(config?: DeepgramSTTConfig): UseDeepgramSTTReturn {
    42→  const [isListening, setIsListening] = useState(false);
    43→  const [transcript, setTranscript] = useState("");
    44→  const [interimTranscript, setInterimTranscript] = useState("");
    45→  const wsRef = useRef<WebSocket | null>(null);
    46→  const streamRef = useRef<MediaStream | null>(null);
    47→  const audioCtxRef = useRef<AudioContext | null>(null);
    48→  const processorRef = useRef<ScriptProcessorNode | null>(null);
    49→  const resumeIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    50→  const reconnectCountRef = useRef(0);
    51→  // Track whether a close was intentional (config change) vs unexpected
    52→  const intentionalCloseRef = useRef(false);
    53→
    54→  const activeConfig = config ?? DEFAULT_CONFIG;
    55→  // Store config in a ref so connectWebSocket always sees the latest values
    56→  const configRef = useRef(activeConfig);
    57→  configRef.current = activeConfig;
    58→
    59→  const cleanup = useCallback(() => {
    60→    if (resumeIntervalRef.current) {
    61→      clearInterval(resumeIntervalRef.current);
    62→      resumeIntervalRef.current = null;
    63→    }
    64→    processorRef.current?.disconnect();
    65→    processorRef.current = null;
    66→    audioCtxRef.current?.close().catch(() => {});
    67→    audioCtxRef.current = null;
    68→    streamRef.current?.getTracks().forEach((t) => t.stop());
    69→    streamRef.current = null;
    70→    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
    71→      wsRef.current.close();
    72→    }
    73→    wsRef.current = null;
    74→    reconnectCountRef.current = 0;
    75→    setIsListening(false);
    76→    setInterimTranscript("");
    77→  }, []);
    78→
    79→  const connectWebSocket = useCallback(
    80→    (stream: MediaStream) => {
    81→      if (!DEEPGRAM_API_KEY) {
    82→        console.warn("[DeepgramSTT] No API key configured");
    83→        return;
    84→      }
    85→
    86→      const url = buildDeepgramUrl(configRef.current);
    87→      console.log("[DeepgramSTT] Connecting with URL:", url);
    88→      const ws = new WebSocket(url, ["token", DEEPGRAM_API_KEY]);
    89→      wsRef.current = ws;
    90→
    91→      ws.onopen = () => {
    92→        console.log("[MirrorV2:STT] Connected to Deepgram");
    93→        setIsListening(true);
    94→        reconnectCountRef.current = 0;
    95→
    96→        // Clean up old audio pipeline if reconnecting
    97→        if (resumeIntervalRef.current) {
    98→          clearInterval(resumeIntervalRef.current);
    99→          resumeIntervalRef.current = null;
   100→        }
   101→        processorRef.current?.disconnect();
   102→        audioCtxRef.current?.close().catch(() => {});
   103→
   104→        // Create fresh audio pipeline: mic → AudioContext → ScriptProcessor → WebSocket
   105→        const audioCtx = new AudioContext({ sampleRate: 16000 });
   106→        audioCtxRef.current = audioCtx;
   107→        const source = audioCtx.createMediaStreamSource(stream);
   108→        const processor = audioCtx.createScriptProcessor(4096, 1, 1);
   109→        processorRef.current = processor;
   110→
   111→        processor.onaudioprocess = (e) => {
   112→          if (ws.readyState !== WebSocket.OPEN) return;
   113→          const float32 = e.inputBuffer.getChannelData(0);
   114→          // Convert Float32 PCM to Int16 PCM
   115→          const int16 = new Int16Array(float32.length);
   116→          for (let i = 0; i < float32.length; i++) {
   117→            const s = Math.max(-1, Math.min(1, float32[i]));
   118→            int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
   119→          }
   120→          ws.send(int16.buffer);
   121→        };
   122→
   123→        source.connect(processor);
   124→        processor.connect(audioCtx.destination);
   125→
   126→        // Periodically resume AudioContext if browser suspends it (tab switch / idle)
   127→        resumeIntervalRef.current = setInterval(() => {
   128→          if (audioCtx.state === "suspended") {
   129→            audioCtx.resume().catch(() => {});
   130→          }
   131→        }, 3000);
   132→      };
   133→
   134→      ws.onmessage = (event) => {
   135→        try {
   136→          const data = JSON.parse(event.data);
   137→
   138→          // Handle utterance end — clear interim
   139→          if (data.type === "UtteranceEnd") {
   140→            setInterimTranscript("");
   141→            return;
   142→          }
   143→
   144→          const alt = data.channel?.alternatives?.[0];
   145→          if (!alt) return;
   146→
   147→          const text = alt.transcript;
   148→          if (!text) return;
   149→
   150→          if (data.is_final) {
   151→            console.log("[STT] Final transcript:", text);
   152→            setTranscript(text);
   153→            setInterimTranscript("");
   154→          } else {
   155→            setInterimTranscript(text);
   156→          }
   157→        } catch {
   158→          console.warn("[MirrorV2:STT] Non-JSON message received");
   159→        }
   160→      };
   161→
   162→      ws.onclose = (event) => {
   163→        console.warn("[MirrorV2:STT] Disconnected:", event.reason || `code=${event.code}`);
   164→
   165→        // If this was an intentional close (config change), don't auto-reconnect
   166→        if (intentionalCloseRef.current) {
   167→          intentionalCloseRef.current = false;
   168→          return;
   169→        }
   170→
   171→        // Exponential backoff reconnect (max 3 attempts)
   172→        if (reconnectCountRef.current < MAX_RECONNECTS && streamRef.current) {
   173→          reconnectCountRef.current += 1;
   174→          const delay = Math.min(1000 * Math.pow(2, reconnectCountRef.current - 1), 5000);
   175→          console.warn(`[MirrorV2:STT] Reconnecting, attempt: ${reconnectCountRef.current}/${MAX_RECONNECTS} in ${delay}ms`);
   176→          setTimeout(() => {
   177→            if (streamRef.current) {
   178→              connectWebSocket(streamRef.current);
   179→            }
   180→          }, delay);
   181→        } else if (reconnectCountRef.current >= MAX_RECONNECTS) {
   182→          console.error("[MirrorV2:STT] Max reconnects reached, STT offline");
   183→          setIsListening(false);
   184→        } else {
   185→          setIsListening(false);
   186→        }
   187→      };
   188→
   189→      ws.onerror = () => {
   190→        ws.close();
   191→      };
   192→    },
   193→    [cleanup],
   194→  );
   195→
   196→  // Reconnect WebSocket when config changes (while already listening)
   197→  useEffect(() => {
   198→    if (!wsRef.current || !streamRef.current) return;
   199→
   200→    console.log("[DeepgramSTT] Config changed, reconnecting...");
   201→    intentionalCloseRef.current = true;
   202→    reconnectCountRef.current = 0;
   203→
   204→    // Close existing WebSocket — intentionalCloseRef prevents auto-reconnect in onclose
   205→    if (wsRef.current.readyState <= WebSocket.OPEN) {
   206→      wsRef.current.close();
   207→    }
   208→    wsRef.current = null;
   209→
   210→    // Reconnect with existing mic stream (no re-prompt)
   211→    connectWebSocket(streamRef.current);
   212→    // eslint-disable-next-line react-hooks/exhaustive-deps
   213→  }, [activeConfig.utterance_end_ms, activeConfig.model, activeConfig.smart_format]);
   214→
   215→  const startListening = useCallback(async () => {
   216→    if (wsRef.current) return;
   217→    reconnectCountRef.current = 0;
   218→
   219→    try {
   220→      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
   221→      streamRef.current = stream;
   222→      connectWebSocket(stream);
   223→    } catch (err) {
   224→      console.error("[MirrorV2:STT] Microphone access failed:", err instanceof Error ? err.message : err);
   225→    }
   226→  }, [connectWebSocket]);
   227→
   228→  const stopListening = useCallback(() => {
   229→    cleanup();
   230→  }, [cleanup]);
   231→
   232→  return { isListening, transcript, interimTranscript, startListening, stopListening };
   233→}
