### Overview
Add in-memory tracking of active and recent scrape jobs with status, phase, and purchase count. Display on admin dashboard for real-time monitoring.

**Design rationale:** In-memory tracking (not DB) — scrape jobs are transient, server restart loss is acceptable for an admin monitoring tool. Max 50 recent jobs retained.

### Implementation Steps

#### 1. Backend: Add In-Memory Job Tracking (`backend/scraper/routes.py`)

**After imports (line 21)** - Add job tracking data structures:

```python
from datetime import datetime
from collections import OrderedDict
from typing import Optional

# In-memory scrape job tracker (max 50 recent jobs)
_scrape_jobs: OrderedDict[str, dict] = OrderedDict()
MAX_SCRAPE_JOBS = 50

def _add_scrape_job(user_id: str, user_name: str) -> None:
    """Create a new scrape job entry."""
    _scrape_jobs[user_id] = {
        "user_id": user_id,
        "user_name": user_name,
        "status": "running",
        "phase": "searching",
        "purchases_found": 0,
        "started_at": datetime.utcnow().isoformat(),
        "completed_at": None,
        "error": None,
    }
    # Evict oldest completed job if we exceed max
    if len(_scrape_jobs) > MAX_SCRAPE_JOBS:
        for uid, job in list(_scrape_jobs.items()):
            if job["status"] in ("completed", "failed"):
                del _scrape_jobs[uid]
                break

def _update_scrape_job(user_id: str, **updates) -> None:
    """Update an existing scrape job."""
    if user_id in _scrape_jobs:
        _scrape_jobs[user_id].update(updates)

def _complete_scrape_job(user_id: str, status: str, error: Optional[str] = None) -> None:
    """Mark a scrape job as completed or failed."""
    if user_id in _scrape_jobs:
        _scrape_jobs[user_id].update({
            "status": status,
            "completed_at": datetime.utcnow().isoformat(),
            "error": error,
        })
```

