function ScrapeJobRow({ job }: { job: ScrapeJob }) {
  const statusColors = {
    running: "bg-blue-100 text-blue-700",
    completed: "bg-green-100 text-green-700",
    failed: "bg-red-100 text-red-700",
  };

  const phaseLabels = {
    searching: "Searching emails",
    parsing: "Parsing purchases",
    profiling: "Building profile",
    complete: "Complete",
  };

  const elapsed = job.completed_at
    ? Math.round(
        (new Date(job.completed_at).getTime() - new Date(job.started_at).getTime()) / 1000
      )
    : Math.round((Date.now() - new Date(job.started_at).getTime()) / 1000);

  return (
    <div className="py-3">
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-2">
          <span className="font-medium">{job.user_name}</span>
          <span
            className={`text-xs px-2 py-0.5 rounded-full font-medium ${
              statusColors[job.status]
            }`}
          >
            {job.status}
          </span>
        </div>
        <span className="text-xs text-zinc-400">
          {elapsed}s
          {job.status === "running" && " ago"}
        </span>
      </div>
      <div className="flex items-center gap-3 text-sm text-zinc-500">
        <span>{phaseLabels[job.phase]}</span>
        <span>•</span>
        <span>{job.purchases_found} purchases found</span>
        {job.error && (
          <>
            <span>•</span>
            <span className="text-red-500 text-xs truncate max-w-xs">
              Error: {job.error}
            </span>
          </>
        )}
      </div>
    </div>
  );
}
```

